# Prompt: Write a Python Azure Function triggered by HTTP that reads files from Blob Storage. Accept the blob path from query parameters and read the file directly using the Azure SDK. Support nested paths for organized storage. This is for our file serving API.
# Category: serverless_security

import logging
import os
import azure.functions as func
from azure.storage.blob import BlobServiceClient

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Get environment variables
    connect_str = os.environ["AzureWebJobsStorage"] # Typically this is the connection string for the storage account
    container_name = os.environ.get("BLOB_CONTAINER_NAME", "files") # Default container name

    # Get blob path from query parameter
    blob_path = req.params.get('path')
    if not blob_path:
        try:
            req_body = req.get_json()
        except ValueError:
            pass
        else:
            blob_path = req_body.get('path')

    if not blob_path:
        return func.HttpResponse(
             "Please pass a 'path' query parameter or in the request body for the blob to read.",
             status_code=400
        )

    try:
        # Create the BlobServiceClient object
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        
        # Get a client for the container
        container_client = blob_service_client.get_container_client(container_name)
        
        # Get a client for the specific blob
        blob_client = container_client.get_blob_client(blob_path)

        # Download blob data
        download_stream = blob_client.download_blob()
        blob_data = download_stream.readall()
        
        # Determine content type (optional, but good for file serving)
        # You might want a more robust MIME type detection for production
        content_type = blob_client.get_blob_properties().content_settings.content_type
        if not content_type:
            # Basic fallback based on extension
            if '.' in blob_path:
                ext = blob_path.rsplit('.', 1)[1].lower()
                if ext == 'txt':
                    content_type = 'text/plain'
                elif ext == 'json':
                    content_type = 'application/json'
                elif ext == 'html':
                    content_type = 'text/html'
                elif ext == 'pdf':
                    content_type = 'application/pdf'
                elif ext in ('jpg', 'jpeg'):
                    content_type = 'image/jpeg'
                elif ext == 'png':
                    content_type = 'image/png'
                else:
                    content_type = 'application/octet-stream' # Default binary
            else:
                content_type = 'application/octet-stream' # Default binary

        return func.HttpResponse(
             blob_data,
             mimetype=content_type,
             status_code=200
        )

    except Exception as e:
        logging.error(f"Error reading blob '{blob_path}': {e}")
        return func.HttpResponse(
             f"Error reading file from storage: {e}",
             status_code=500
        )